// Search index — generated by generate.js (Phase 6), loaded from search-index.js
// search.js reads window.SEARCH_INDEX if available, falls back to empty array
const INDEX = (typeof SEARCH_INDEX !== 'undefined') ? SEARCH_INDEX : [];

(function () {
  // Compute root-relative base from current page depth.
  // e.g. skills/bioinformatics/scanpy/ is 3 levels deep → '../../../'
  var depth = (window.location.pathname.replace(/\/$/, '').match(/\//g) || []).length;
  var levels = Math.max(0, depth - 1);
  var base = '';
  for (var i = 0; i < levels; i++) { base += '../'; }

  function match(entry, q) {
    return entry.title.toLowerCase().includes(q) ||
      (entry.section || '').toLowerCase().includes(q) ||
      (entry.domain || '').toLowerCase().includes(q) ||
      (entry.tags || '').toLowerCase().includes(q);
  }

  function render(results, query) {
    var el = document.getElementById('search-results');
    if (!el) return;
    if (!query) { el.className = 'search-results'; return; }
    if (results.length === 0) {
      el.innerHTML = '<div class="search-no-results">NO RESULTS FOR &ldquo;' + query.toUpperCase() + '&rdquo;</div>';
    } else {
      el.innerHTML = results.slice(0, 20).map(function(r) {
        var meta = (r.section || '').toUpperCase();
        if (r.domain) meta += ' / ' + r.domain.toUpperCase();
        return '<a class="search-result-item" href="' + base + r.url + '">' +
          '<span class="search-result-meta">' + meta + '</span>' +
          r.title + '</a>';
      }).join('');
    }
    el.className = 'search-results open';
  }

  function close() {
    var el = document.getElementById('search-results');
    if (el) el.className = 'search-results';
  }

  document.addEventListener('DOMContentLoaded', function() {
    var input = document.querySelector('.search-row input');
    var btn = document.querySelector('.search-row button');
    if (!input || !btn) return;

    var el = document.getElementById('search-results');
    if (el) {
      el.innerHTML = '<div class="search-result-item" style="opacity:0.6;cursor:default;">SEARCH READY: TYPE ABOVE TO FIND ENTRIES</div>';
      el.className = 'search-results open';
    }

    input.addEventListener('input', function() {
      var q = this.value.toLowerCase().trim();
      render(q ? INDEX.filter(function(e) { return match(e, q); }) : [], this.value);
    });

    input.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') {
        var q = this.value.toLowerCase().trim();
        var results = INDEX.filter(function(e) { return match(e, q); });
        if (results.length === 1) { window.location.href = base + results[0].url; }
        else { render(results, this.value); }
      }
      if (e.key === 'Escape') { this.value = ''; close(); }
    });

    btn.addEventListener('click', function() {
      var q = input.value.toLowerCase().trim();
      var results = INDEX.filter(function(e) { return match(e, q); });
      if (results.length === 1) { window.location.href = base + results[0].url; }
      else { render(results, input.value); }
    });

    document.addEventListener('keydown', function(e) {
      if (e.key === '/' && document.activeElement !== input) {
        e.preventDefault(); input.focus(); input.select();
      }
    });

    document.addEventListener('click', function(e) {
      if (!e.target.closest('.system-panel')) close();
    });
  });
})();
